SELECT user_id, COUNT(*) AS total_clicks
FROM announcement_clicks
GROUP BY user_id;

SELECT notifications.type, COUNT(*) AS count
FROM notifications
GROUP BY notifications.type;

SELECT user_id 
FROM site_feedback 
WHERE rating = 4;

SELECT COUNT(*) AS total_visits
FROM site_visits
WHERE visited_at >= DATE('now', '-1 month');

SELECT title 
FROM announcement_settings 
WHERE start_date = (SELECT MAX(start_date) FROM announcement_settings);

SELECT COUNT(DISTINCT user_id) 
FROM notifications
WHERE message = 'The site title has been updated';

SELECT COUNT(DISTINCT user_id) AS number_of_users
FROM announcement_clicks
WHERE clicked_at >= DATE('now', '-30 days');

SELECT COUNT(user_id) 
FROM site_feedback
WHERE rating = 5;

SELECT content 
FROM help_articles 
WHERE title = 'How to Upload a Logo';

SELECT user_id 
FROM users 
WHERE user_id NOT IN (
  SELECT user_id 
  FROM announcement_clicks
);

SELECT COUNT(*) 
FROM announcement_clicks 
WHERE user_id = 1;

SELECT COUNT(*) 
FROM users 
WHERE user_id NOT IN (SELECT user_id FROM announcement_clicks);

SELECT u.username, u.email, u.last_login_at
FROM users u
INNER JOIN site_feedback sf ON u.user_id = sf.user_id;
